async (params, browser) => {
  // Open financials page
  await browser.open(`https://finance.yahoo.com/quote/${params.symbol}/financials/`)

  // Wait for financial data to load
  await browser.waitForSelector('table, [class*=\'financials\'], [data-testid=\'fin-row\']', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to see more data
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract financial statements
  const financials_data = await browser.evaluate(`const financials = []; const rows = document.querySelectorAll('[data-testid="fin-row"], table tbody tr, [class*="financials"] [class*="row"]'); rows.forEach(function(row) { const labelEl = row.querySelector('[class*="label"], td:first-child, [title]'); const valueCells = row.querySelectorAll('[class*="cell"]:not(:first-child), td:not(:first-child)'); const values = []; valueCells.forEach(function(cell) { values.push(cell.textContent.trim()); }); if (labelEl) { financials.push({ metric: labelEl.getAttribute('title') || labelEl.textContent.trim(), values: values.slice(0, 5) }); } }); const headerCells = document.querySelectorAll('table thead th, [class*="header"] [class*="cell"], [class*="column-header"]'); const periods = []; headerCells.forEach(function(cell) { const text = cell.textContent.trim(); if (text && text.match(/\d{4}|TTM|\d{1,2}\/\d{1,2}\/\d{4}/)) { periods.push(text); } }); const nameEl = document.querySelector('h1, [class*="quote-header"] h1'); return { symbol: '' + params.symbol + '', name: nameEl ? nameEl.textContent.trim() : '', periods: periods.slice(0, 5), row_count: financials.length, financials: financials.slice(0, 30), url: window.location.href }`)

  return financials_data
}
